const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.salesforce&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
if (!creds.salesforce_instance_url || !creds.salesforce_consumer_key || !creds.salesforce_consumer_secret) {
  return [{ json: { error: 'Salesforce credentials missing. Need: salesforce_instance_url, salesforce_consumer_key, salesforce_consumer_secret. Create a "Externe Client-Anwendung" in Setup, enable OAuth with scope "api", enable Client Credentials Flow with a Run-As user, then copy Consumer Key + Secret.' } }];
}

const INSTANCE = String(creds.salesforce_instance_url).replace(/\/+$/, '');
const API_VERSION = 'v60.0';
const API = INSTANCE + '/services/data/' + API_VERSION;

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

function errMsg(err) {
  if (err.response && err.response.body) {
    const b = err.response.body;
    if (typeof b === 'string') return b;
    if (Array.isArray(b) && b[0]) {
      const e = b[0];
      return (e.errorCode ? e.errorCode + ': ' : '') + (e.message || JSON.stringify(e));
    }
    if (b.error_description) return b.error || b.error_description;
    if (b.message) return b.message;
    return JSON.stringify(b);
  }
  if (err.message) return err.message;
  return String(err);
}

// --- Auth: fetch access token via Client Credentials Flow ---
let accessToken;
try {
  const tokenResp = await helpers.httpRequest({
    method: 'POST',
    url: INSTANCE + '/services/oauth2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'grant_type=client_credentials&client_id=' + encodeURIComponent(creds.salesforce_consumer_key) + '&client_secret=' + encodeURIComponent(creds.salesforce_consumer_secret),
    json: true
  });
  accessToken = tokenResp.access_token;
  if (!accessToken) return [{ json: { error: 'Salesforce auth failed: no access_token in response: ' + JSON.stringify(tokenResp) } }];
} catch (err) {
  return [{ json: { error: 'Salesforce auth failed: ' + errMsg(err) + '. Check instance URL, Consumer Key/Secret, and that "Flow for Client Credentials" is enabled with a valid Run-As user in the External Client App.' } }];
}

const authHeaders = { 'Authorization': 'Bearer ' + accessToken };
const jsonHeaders = Object.assign({}, authHeaders, { 'Content-Type': 'application/json' });

async function sfGet(path) {
  return await helpers.httpRequest({ method: 'GET', url: API + path, headers: authHeaders, json: true });
}
async function sfPost(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: API + path, headers: jsonHeaders, body: body, json: true });
}
async function sfPatch(path, body) {
  // Salesforce PATCH returns 204 No Content — don't try to parse JSON
  return await helpers.httpRequest({ method: 'PATCH', url: API + path, headers: jsonHeaders, body: body, json: true, returnFullResponse: false });
}
async function sfDelete(path) {
  return await helpers.httpRequest({ method: 'DELETE', url: API + path, headers: authHeaders });
}
async function sfSoql(query) {
  return await helpers.httpRequest({
    method: 'GET',
    url: API + '/query?q=' + encodeURIComponent(query),
    headers: authHeaders,
    json: true
  });
}
async function sfSosl(query) {
  return await helpers.httpRequest({
    method: 'GET',
    url: API + '/search?q=' + encodeURIComponent(query),
    headers: authHeaders,
    json: true
  });
}

function mergeCustomFields(props, raw) {
  if (!raw) return props;
  let obj;
  try { obj = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { return props; }
  if (obj && typeof obj === 'object') Object.assign(props, obj);
  return props;
}

function buildProps(input, allowed) {
  const props = {};
  for (const f of allowed) if (input[f] !== undefined && input[f] !== '' && input[f] !== null) props[f] = input[f];
  mergeCustomFields(props, input.custom_fields);
  return props;
}

function normOp(op) {
  const o = String(op || '=').toUpperCase();
  if (['=', '!=', '<', '>', '<=', '>=', 'LIKE'].indexOf(o) >= 0) return o;
  return '=';
}

function soqlEscape(s) {
  return String(s).replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

function ymd(s) { return s ? String(s).substring(0, 10) : ''; }

// === CONTACTS ===
if (action === 'list_contacts') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  try {
    const r = await sfSoql('SELECT Id, Name, Email, Phone, Title, Account.Name FROM Contact ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No contacts.' } }];
    let out = 'Contacts (' + items.length + '):\n';
    for (const c of items) {
      out += '  ' + c.Id + ' - ' + (c.Name || '(no name)') + (c.Email ? ' <' + c.Email + '>' : '') + (c.Account && c.Account.Name ? ' @ ' + c.Account.Name : '') + (c.Title ? ' [' + c.Title + ']' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_contacts: ' + errMsg(err) } }]; }

} else if (action === 'search_contacts') {
  const value = input.value;
  if (!value) return [{ json: { error: 'Parameter "value" is required. Default search on Name. Override via "field" (e.g. Email, Phone, Title) and "operator" (=, LIKE, !=). Use % wildcards with LIKE (e.g. value=%edge%).' } }];
  const field = input.field || 'Name';
  const op = normOp(input.operator);
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const soql = 'SELECT Id, Name, Email, Phone, Title, Account.Name FROM Contact WHERE ' + field + ' ' + op + " '" + soqlEscape(value) + "' ORDER BY LastModifiedDate DESC LIMIT " + limit;
  try {
    const r = await sfSoql(soql);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + field + ' ' + op + ' "' + value + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const c of items) {
      out += '  ' + c.Id + ' - ' + (c.Name || '(no name)') + (c.Email ? ' <' + c.Email + '>' : '') + (c.Account && c.Account.Name ? ' @ ' + c.Account.Name : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce search_contacts: ' + errMsg(err) } }]; }

} else if (action === 'get_contact') {
  const id = input.contact_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "contact_id" is required.' } }];
  try {
    const c = await sfGet('/sobjects/Contact/' + encodeURIComponent(id));
    let out = 'Contact ' + c.Id + ' - ' + (c.Name || '(no name)') + '\n';
    if (c.Email) out += 'Email: ' + c.Email + '\n';
    if (c.Phone) out += 'Phone: ' + c.Phone + '\n';
    if (c.Title) out += 'Title: ' + c.Title + '\n';
    if (c.AccountId) out += 'Account: ' + c.AccountId + '\n';
    if (c.MailingCity || c.MailingCountry) out += 'Mailing: ' + [c.MailingCity, c.MailingCountry].filter(Boolean).join(', ') + '\n';
    if (c.Department) out += 'Department: ' + c.Department + '\n';
    if (c.CreatedDate) out += 'Created: ' + ymd(c.CreatedDate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce get_contact: ' + errMsg(err) } }]; }

} else if (action === 'create_contact') {
  if (!input.LastName && !input.lastname) return [{ json: { error: 'Parameter "LastName" is required (Salesforce mandatory field).' } }];
  const aliased = Object.assign({}, input);
  if (input.lastname && !input.LastName) aliased.LastName = input.lastname;
  if (input.firstname && !input.FirstName) aliased.FirstName = input.firstname;
  if (input.email && !input.Email) aliased.Email = input.email;
  if (input.phone && !input.Phone) aliased.Phone = input.phone;
  const props = buildProps(aliased, ['FirstName', 'LastName', 'Email', 'Phone', 'Title', 'AccountId', 'MailingCity', 'MailingCountry', 'MailingState', 'MailingStreet', 'MailingPostalCode', 'Department', 'Description']);
  try {
    const r = await sfPost('/sobjects/Contact', props);
    return [{ json: { result: 'Contact created: ' + r.id + ' - ' + (props.FirstName ? props.FirstName + ' ' : '') + props.LastName } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_contact: ' + errMsg(err) } }]; }

} else if (action === 'update_contact') {
  const id = input.contact_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "contact_id" is required.' } }];
  const props = buildProps(input, ['FirstName', 'LastName', 'Email', 'Phone', 'Title', 'AccountId', 'MailingCity', 'MailingCountry', 'MailingState', 'MailingStreet', 'MailingPostalCode', 'Department', 'Description']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field (FirstName, LastName, Email, Phone, Title, AccountId, MailingCity, MailingCountry, ...) or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Contact/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Contact ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_contact: ' + errMsg(err) } }]; }

} else if (action === 'delete_contact') {
  const id = input.contact_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "contact_id" is required.' } }];
  try {
    await sfDelete('/sobjects/Contact/' + encodeURIComponent(id));
    return [{ json: { result: 'Contact ' + id + ' deleted (moved to Recycle Bin, restorable for 15 days).' } }];
  } catch (err) { return [{ json: { error: 'Salesforce delete_contact: ' + errMsg(err) } }]; }

// === ACCOUNTS ===
} else if (action === 'list_accounts') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  try {
    const r = await sfSoql('SELECT Id, Name, Industry, Phone, Website, BillingCity, BillingCountry FROM Account ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No accounts.' } }];
    let out = 'Accounts (' + items.length + '):\n';
    for (const a of items) {
      out += '  ' + a.Id + ' - ' + (a.Name || '(no name)') + (a.Industry ? ' [' + a.Industry + ']' : '') + (a.BillingCountry ? ' ' + a.BillingCountry : '') + (a.Website ? ' ' + a.Website : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_accounts: ' + errMsg(err) } }]; }

} else if (action === 'search_accounts') {
  const value = input.value;
  if (!value) return [{ json: { error: 'Parameter "value" is required. Default search on Name. Override via "field" and "operator".' } }];
  const field = input.field || 'Name';
  const op = normOp(input.operator);
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const soql = 'SELECT Id, Name, Industry, Phone, Website, BillingCountry FROM Account WHERE ' + field + ' ' + op + " '" + soqlEscape(value) + "' ORDER BY LastModifiedDate DESC LIMIT " + limit;
  try {
    const r = await sfSoql(soql);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + field + ' ' + op + ' "' + value + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const a of items) {
      out += '  ' + a.Id + ' - ' + (a.Name || '(no name)') + (a.Industry ? ' [' + a.Industry + ']' : '') + (a.BillingCountry ? ' ' + a.BillingCountry : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce search_accounts: ' + errMsg(err) } }]; }

} else if (action === 'get_account') {
  const id = input.account_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "account_id" is required.' } }];
  try {
    const a = await sfGet('/sobjects/Account/' + encodeURIComponent(id));
    let out = 'Account ' + a.Id + ' - ' + (a.Name || '(no name)') + '\n';
    if (a.Industry) out += 'Industry: ' + a.Industry + '\n';
    if (a.Phone) out += 'Phone: ' + a.Phone + '\n';
    if (a.Website) out += 'Website: ' + a.Website + '\n';
    const loc = [a.BillingCity, a.BillingState, a.BillingCountry].filter(Boolean).join(', ');
    if (loc) out += 'Billing: ' + loc + '\n';
    if (a.NumberOfEmployees) out += 'Employees: ' + a.NumberOfEmployees + '\n';
    if (a.AnnualRevenue) out += 'Revenue: ' + a.AnnualRevenue + '\n';
    if (a.Type) out += 'Type: ' + a.Type + '\n';
    if (a.Description) out += 'Description: ' + String(a.Description).substring(0, 300) + '\n';
    if (a.CreatedDate) out += 'Created: ' + ymd(a.CreatedDate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce get_account: ' + errMsg(err) } }]; }

} else if (action === 'create_account') {
  if (!input.Name && !input.name) return [{ json: { error: 'Parameter "Name" is required.' } }];
  const aliased = Object.assign({}, input);
  if (input.name && !input.Name) aliased.Name = input.name;
  const props = buildProps(aliased, ['Name', 'Phone', 'Website', 'Industry', 'BillingCity', 'BillingState', 'BillingCountry', 'BillingStreet', 'BillingPostalCode', 'Description', 'NumberOfEmployees', 'AnnualRevenue', 'Type']);
  try {
    const r = await sfPost('/sobjects/Account', props);
    return [{ json: { result: 'Account created: ' + r.id + ' - ' + props.Name } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_account: ' + errMsg(err) } }]; }

} else if (action === 'update_account') {
  const id = input.account_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "account_id" is required.' } }];
  const props = buildProps(input, ['Name', 'Phone', 'Website', 'Industry', 'BillingCity', 'BillingState', 'BillingCountry', 'BillingStreet', 'BillingPostalCode', 'Description', 'NumberOfEmployees', 'AnnualRevenue', 'Type']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Account/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Account ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_account: ' + errMsg(err) } }]; }

} else if (action === 'delete_account') {
  const id = input.account_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "account_id" is required.' } }];
  try {
    await sfDelete('/sobjects/Account/' + encodeURIComponent(id));
    return [{ json: { result: 'Account ' + id + ' deleted (moved to Recycle Bin).' } }];
  } catch (err) { return [{ json: { error: 'Salesforce delete_account: ' + errMsg(err) } }]; }

// === LEADS ===
} else if (action === 'list_leads') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const includeConverted = String(input.include_converted || '').toLowerCase() === 'true';
  const where = includeConverted ? '' : ' WHERE IsConverted = false';
  try {
    const r = await sfSoql('SELECT Id, Name, Company, Email, Phone, Status, LeadSource, IsConverted FROM Lead' + where + ' ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No leads.' } }];
    let out = 'Leads (' + items.length + '):\n';
    for (const l of items) {
      out += '  ' + l.Id + ' - ' + (l.Name || '(no name)') + (l.Company ? ' @ ' + l.Company : '') + (l.Status ? ' [' + l.Status + ']' : '') + (l.Email ? ' <' + l.Email + '>' : '') + (l.IsConverted ? ' (converted)' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_leads: ' + errMsg(err) } }]; }

} else if (action === 'search_leads') {
  const value = input.value;
  if (!value) return [{ json: { error: 'Parameter "value" is required. Common fields: Name, Company, Email, Status, LeadSource, Rating.' } }];
  const field = input.field || 'Name';
  const op = normOp(input.operator);
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const soql = 'SELECT Id, Name, Company, Email, Phone, Status, LeadSource, Rating, IsConverted FROM Lead WHERE ' + field + ' ' + op + " '" + soqlEscape(value) + "' ORDER BY LastModifiedDate DESC LIMIT " + limit;
  try {
    const r = await sfSoql(soql);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + field + ' ' + op + ' "' + value + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const l of items) {
      out += '  ' + l.Id + ' - ' + (l.Name || '(no name)') + (l.Company ? ' @ ' + l.Company : '') + (l.Status ? ' [' + l.Status + ']' : '') + (l.Email ? ' <' + l.Email + '>' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce search_leads: ' + errMsg(err) } }]; }

} else if (action === 'get_lead') {
  const id = input.lead_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "lead_id" is required.' } }];
  try {
    const l = await sfGet('/sobjects/Lead/' + encodeURIComponent(id));
    let out = 'Lead ' + l.Id + ' - ' + (l.Name || '(no name)') + '\n';
    if (l.Company) out += 'Company: ' + l.Company + '\n';
    if (l.Email) out += 'Email: ' + l.Email + '\n';
    if (l.Phone) out += 'Phone: ' + l.Phone + '\n';
    if (l.Title) out += 'Title: ' + l.Title + '\n';
    if (l.Status) out += 'Status: ' + l.Status + '\n';
    if (l.LeadSource) out += 'Source: ' + l.LeadSource + '\n';
    if (l.Rating) out += 'Rating: ' + l.Rating + '\n';
    if (l.Industry) out += 'Industry: ' + l.Industry + '\n';
    if (typeof l.IsConverted !== 'undefined') out += 'Converted: ' + (l.IsConverted ? 'yes' : 'no') + '\n';
    if (l.CreatedDate) out += 'Created: ' + ymd(l.CreatedDate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce get_lead: ' + errMsg(err) } }]; }

} else if (action === 'create_lead') {
  const aliased = Object.assign({}, input);
  if (input.lastname && !input.LastName) aliased.LastName = input.lastname;
  if (input.firstname && !input.FirstName) aliased.FirstName = input.firstname;
  if (input.company && !input.Company) aliased.Company = input.company;
  if (input.email && !input.Email) aliased.Email = input.email;
  if (!aliased.LastName) return [{ json: { error: 'Parameter "LastName" is required.' } }];
  if (!aliased.Company) return [{ json: { error: 'Parameter "Company" is required for Lead.' } }];
  const props = buildProps(aliased, ['FirstName', 'LastName', 'Company', 'Email', 'Phone', 'Title', 'Status', 'LeadSource', 'Rating', 'Industry', 'Street', 'City', 'State', 'Country', 'PostalCode', 'Description', 'NumberOfEmployees', 'AnnualRevenue']);
  try {
    const r = await sfPost('/sobjects/Lead', props);
    return [{ json: { result: 'Lead created: ' + r.id + ' - ' + (props.FirstName ? props.FirstName + ' ' : '') + props.LastName + ' @ ' + props.Company } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_lead: ' + errMsg(err) } }]; }

} else if (action === 'update_lead') {
  const id = input.lead_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "lead_id" is required.' } }];
  const props = buildProps(input, ['FirstName', 'LastName', 'Company', 'Email', 'Phone', 'Title', 'Status', 'LeadSource', 'Rating', 'Industry', 'Street', 'City', 'State', 'Country', 'PostalCode', 'Description']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Lead/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Lead ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_lead: ' + errMsg(err) } }]; }

} else if (action === 'delete_lead') {
  const id = input.lead_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "lead_id" is required.' } }];
  try {
    await sfDelete('/sobjects/Lead/' + encodeURIComponent(id));
    return [{ json: { result: 'Lead ' + id + ' deleted (moved to Recycle Bin).' } }];
  } catch (err) { return [{ json: { error: 'Salesforce delete_lead: ' + errMsg(err) } }]; }

// === OPPORTUNITIES ===
} else if (action === 'list_opportunities') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const openOnly = String(input.open_only || '').toLowerCase() === 'true';
  const where = openOnly ? " WHERE IsClosed = false" : '';
  try {
    const r = await sfSoql('SELECT Id, Name, StageName, Amount, CloseDate, Probability, Account.Name FROM Opportunity' + where + ' ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No opportunities.' } }];
    let out = 'Opportunities (' + items.length + '):\n';
    for (const o of items) {
      out += '  ' + o.Id + ' - ' + (o.Name || '(no name)') + (o.Amount ? ' ' + o.Amount : '') + (o.StageName ? ' [' + o.StageName + ']' : '') + (o.CloseDate ? ' close: ' + ymd(o.CloseDate) : '') + (o.Account && o.Account.Name ? ' @ ' + o.Account.Name : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_opportunities: ' + errMsg(err) } }]; }

} else if (action === 'search_opportunities') {
  const value = input.value;
  if (!value) return [{ json: { error: 'Parameter "value" is required. Common fields: Name, StageName, Amount, CloseDate, OwnerId.' } }];
  const field = input.field || 'Name';
  const op = normOp(input.operator);
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  // Numeric fields like Amount shouldn't be wrapped in quotes
  const isNumeric = ['Amount', 'Probability', 'ExpectedRevenue', 'NumberOfEmployees'].indexOf(field) >= 0;
  const quoted = isNumeric ? String(value) : "'" + soqlEscape(value) + "'";
  const soql = 'SELECT Id, Name, StageName, Amount, CloseDate, Account.Name FROM Opportunity WHERE ' + field + ' ' + op + ' ' + quoted + ' ORDER BY LastModifiedDate DESC LIMIT ' + limit;
  try {
    const r = await sfSoql(soql);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + field + ' ' + op + ' "' + value + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const o of items) {
      out += '  ' + o.Id + ' - ' + (o.Name || '(no name)') + (o.Amount ? ' ' + o.Amount : '') + (o.StageName ? ' [' + o.StageName + ']' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce search_opportunities: ' + errMsg(err) } }]; }

} else if (action === 'get_opportunity') {
  const id = input.opportunity_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "opportunity_id" is required.' } }];
  try {
    const o = await sfGet('/sobjects/Opportunity/' + encodeURIComponent(id));
    let out = 'Opportunity ' + o.Id + ' - ' + (o.Name || '(no name)') + '\n';
    if (o.Amount) out += 'Amount: ' + o.Amount + '\n';
    if (o.StageName) out += 'Stage: ' + o.StageName + '\n';
    if (typeof o.Probability !== 'undefined' && o.Probability !== null) out += 'Probability: ' + o.Probability + '%\n';
    if (o.CloseDate) out += 'Close date: ' + ymd(o.CloseDate) + '\n';
    if (o.AccountId) out += 'Account: ' + o.AccountId + '\n';
    if (o.OwnerId) out += 'Owner: ' + o.OwnerId + '\n';
    if (o.Type) out += 'Type: ' + o.Type + '\n';
    if (o.LeadSource) out += 'Source: ' + o.LeadSource + '\n';
    if (typeof o.IsClosed !== 'undefined') out += 'Closed: ' + (o.IsClosed ? 'yes' : 'no') + (o.IsWon ? ' (won)' : '') + '\n';
    if (o.Description) out += 'Description: ' + String(o.Description).substring(0, 300) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce get_opportunity: ' + errMsg(err) } }]; }

} else if (action === 'create_opportunity') {
  const aliased = Object.assign({}, input);
  if (input.name && !input.Name) aliased.Name = input.name;
  if (input.stagename && !input.StageName) aliased.StageName = input.stagename;
  if (input.closedate && !input.CloseDate) aliased.CloseDate = input.closedate;
  if (input.amount && !input.Amount) aliased.Amount = input.amount;
  if (!aliased.Name) return [{ json: { error: 'Parameter "Name" is required.' } }];
  if (!aliased.StageName) return [{ json: { error: 'Parameter "StageName" is required (use describe_object Opportunity -> StageName picklist for valid values).' } }];
  if (!aliased.CloseDate) return [{ json: { error: 'Parameter "CloseDate" (YYYY-MM-DD) is required.' } }];
  const props = buildProps(aliased, ['Name', 'StageName', 'CloseDate', 'Amount', 'AccountId', 'Probability', 'Type', 'LeadSource', 'Description', 'OwnerId', 'NextStep']);
  try {
    const r = await sfPost('/sobjects/Opportunity', props);
    return [{ json: { result: 'Opportunity created: ' + r.id + ' - ' + props.Name + ' [' + props.StageName + ']' } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_opportunity: ' + errMsg(err) } }]; }

} else if (action === 'update_opportunity') {
  const id = input.opportunity_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "opportunity_id" is required.' } }];
  const props = buildProps(input, ['Name', 'StageName', 'CloseDate', 'Amount', 'AccountId', 'Probability', 'Type', 'LeadSource', 'Description', 'OwnerId', 'NextStep']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Opportunity/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Opportunity ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_opportunity: ' + errMsg(err) } }]; }

} else if (action === 'delete_opportunity') {
  const id = input.opportunity_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "opportunity_id" is required.' } }];
  try {
    await sfDelete('/sobjects/Opportunity/' + encodeURIComponent(id));
    return [{ json: { result: 'Opportunity ' + id + ' deleted (moved to Recycle Bin).' } }];
  } catch (err) { return [{ json: { error: 'Salesforce delete_opportunity: ' + errMsg(err) } }]; }

// === CASES ===
} else if (action === 'list_cases') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const openOnly = String(input.open_only || '').toLowerCase() === 'true';
  const where = openOnly ? " WHERE IsClosed = false" : '';
  try {
    const r = await sfSoql('SELECT Id, CaseNumber, Subject, Status, Priority, Origin, Account.Name FROM Case' + where + ' ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No cases.' } }];
    let out = 'Cases (' + items.length + '):\n';
    for (const c of items) {
      out += '  ' + c.Id + ' #' + (c.CaseNumber || '') + ' - ' + (c.Subject || '(no subject)') + (c.Status ? ' [' + c.Status + ']' : '') + (c.Priority ? ' ' + c.Priority : '') + (c.Account && c.Account.Name ? ' @ ' + c.Account.Name : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_cases: ' + errMsg(err) } }]; }

} else if (action === 'get_case') {
  const id = input.case_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "case_id" is required.' } }];
  try {
    const c = await sfGet('/sobjects/Case/' + encodeURIComponent(id));
    let out = 'Case ' + c.Id + ' #' + (c.CaseNumber || '') + '\n';
    if (c.Subject) out += 'Subject: ' + c.Subject + '\n';
    if (c.Status) out += 'Status: ' + c.Status + '\n';
    if (c.Priority) out += 'Priority: ' + c.Priority + '\n';
    if (c.Origin) out += 'Origin: ' + c.Origin + '\n';
    if (c.Type) out += 'Type: ' + c.Type + '\n';
    if (c.Reason) out += 'Reason: ' + c.Reason + '\n';
    if (c.ContactId) out += 'Contact: ' + c.ContactId + '\n';
    if (c.AccountId) out += 'Account: ' + c.AccountId + '\n';
    if (c.OwnerId) out += 'Owner: ' + c.OwnerId + '\n';
    if (c.Description) out += 'Description: ' + String(c.Description).substring(0, 500) + '\n';
    if (c.CreatedDate) out += 'Created: ' + ymd(c.CreatedDate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce get_case: ' + errMsg(err) } }]; }

} else if (action === 'create_case') {
  if (!input.Subject && !input.subject) return [{ json: { error: 'Parameter "Subject" is required.' } }];
  const aliased = Object.assign({}, input);
  if (input.subject && !input.Subject) aliased.Subject = input.subject;
  if (input.description && !input.Description) aliased.Description = input.description;
  const props = buildProps(aliased, ['Subject', 'Description', 'Status', 'Priority', 'Origin', 'Type', 'Reason', 'ContactId', 'AccountId', 'OwnerId']);
  try {
    const r = await sfPost('/sobjects/Case', props);
    return [{ json: { result: 'Case created: ' + r.id + ' - ' + props.Subject } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_case: ' + errMsg(err) } }]; }

} else if (action === 'update_case') {
  const id = input.case_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "case_id" is required.' } }];
  const props = buildProps(input, ['Subject', 'Description', 'Status', 'Priority', 'Origin', 'Type', 'Reason', 'ContactId', 'AccountId', 'OwnerId']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Case/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Case ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_case: ' + errMsg(err) } }]; }

} else if (action === 'delete_case') {
  const id = input.case_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "case_id" is required.' } }];
  try {
    await sfDelete('/sobjects/Case/' + encodeURIComponent(id));
    return [{ json: { result: 'Case ' + id + ' deleted (moved to Recycle Bin).' } }];
  } catch (err) { return [{ json: { error: 'Salesforce delete_case: ' + errMsg(err) } }]; }

// === TASKS ===
} else if (action === 'list_tasks') {
  const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 200);
  const openOnly = String(input.open_only || '').toLowerCase() === 'true';
  const whoId = input.who_id;
  const wheres = [];
  if (openOnly) wheres.push("Status != 'Completed'");
  if (whoId) wheres.push("WhoId = '" + soqlEscape(whoId) + "'");
  const where = wheres.length ? ' WHERE ' + wheres.join(' AND ') : '';
  try {
    const r = await sfSoql('SELECT Id, Subject, Status, Priority, ActivityDate, WhoId, WhatId, OwnerId FROM Task' + where + ' ORDER BY LastModifiedDate DESC LIMIT ' + limit);
    const items = r.records || [];
    if (items.length === 0) return [{ json: { result: 'No tasks.' } }];
    let out = 'Tasks (' + items.length + '):\n';
    for (const t of items) {
      out += '  ' + t.Id + ' - ' + (t.Subject || '(no subject)') + (t.Status ? ' [' + t.Status + ']' : '') + (t.Priority ? ' ' + t.Priority : '') + (t.ActivityDate ? ' due: ' + ymd(t.ActivityDate) : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce list_tasks: ' + errMsg(err) } }]; }

} else if (action === 'create_task') {
  if (!input.Subject && !input.subject) return [{ json: { error: 'Parameter "Subject" is required.' } }];
  const aliased = Object.assign({}, input);
  if (input.subject && !input.Subject) aliased.Subject = input.subject;
  if (input.description && !input.Description) aliased.Description = input.description;
  const props = buildProps(aliased, ['Subject', 'Description', 'Status', 'Priority', 'ActivityDate', 'WhoId', 'WhatId', 'OwnerId', 'Type']);
  try {
    const r = await sfPost('/sobjects/Task', props);
    return [{ json: { result: 'Task created: ' + r.id + ' - ' + props.Subject } }];
  } catch (err) { return [{ json: { error: 'Salesforce create_task: ' + errMsg(err) } }]; }

} else if (action === 'update_task') {
  const id = input.task_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "task_id" is required.' } }];
  const props = buildProps(input, ['Subject', 'Description', 'Status', 'Priority', 'ActivityDate', 'WhoId', 'WhatId', 'OwnerId', 'Type']);
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field or custom_fields.' } }];
  try {
    await sfPatch('/sobjects/Task/' + encodeURIComponent(id), props);
    return [{ json: { result: 'Task ' + id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'Salesforce update_task: ' + errMsg(err) } }]; }

// === GENERIC ===
} else if (action === 'soql_query') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Full SOQL string, e.g. "SELECT Id, Name FROM Contact WHERE Email LIKE \'%@edge.com\' LIMIT 10".' } }];
  try {
    const r = await sfSoql(query);
    const items = r.records || [];
    const total = r.totalSize || items.length;
    if (items.length === 0) return [{ json: { result: 'Query returned 0 records.' } }];
    let out = 'Query returned ' + items.length + (total > items.length ? ' of ' + total : '') + ' records:\n';
    for (const rec of items) {
      const kv = [];
      for (const k of Object.keys(rec)) {
        if (k === 'attributes') continue;
        const v = rec[k];
        if (v === null || v === undefined) continue;
        if (typeof v === 'object') kv.push(k + '=' + JSON.stringify(v));
        else kv.push(k + '=' + v);
      }
      out += '  ' + kv.join(' | ') + '\n';
    }
    if (!r.done) out += '\n(more results available, use LIMIT/OFFSET to paginate)';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce soql_query: ' + errMsg(err) } }]; }

} else if (action === 'sosl_search') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (search term).' } }];
  const sobjects = input.sobjects || 'Contact,Account,Lead,Opportunity,Case';
  const parts = String(sobjects).split(',').map(function(s){ return s.trim(); }).filter(Boolean);
  const returning = parts.map(function(o){
    if (o === 'Contact') return 'Contact(Id, Name, Email)';
    if (o === 'Account') return 'Account(Id, Name, Industry)';
    if (o === 'Lead') return 'Lead(Id, Name, Company, Status)';
    if (o === 'Opportunity') return 'Opportunity(Id, Name, StageName, Amount)';
    if (o === 'Case') return 'Case(Id, CaseNumber, Subject, Status)';
    return o + '(Id, Name)';
  }).join(', ');
  const sosl = 'FIND {' + String(query).replace(/[{}]/g, '') + '} IN ALL FIELDS RETURNING ' + returning;
  try {
    const r = await sfSosl(sosl);
    const recs = r.searchRecords || [];
    if (recs.length === 0) return [{ json: { result: 'No matches for "' + query + '" across ' + parts.join(', ') + '.' } }];
    let out = 'Search results (' + recs.length + '):\n';
    const byType = {};
    for (const rec of recs) {
      const t = (rec.attributes && rec.attributes.type) || 'Other';
      if (!byType[t]) byType[t] = [];
      byType[t].push(rec);
    }
    for (const t of Object.keys(byType)) {
      out += '\n' + t + ' (' + byType[t].length + '):\n';
      for (const rec of byType[t]) {
        const kv = [];
        for (const k of Object.keys(rec)) {
          if (k === 'attributes') continue;
          const v = rec[k];
          if (v === null || v === undefined) continue;
          kv.push(k + '=' + v);
        }
        out += '  ' + kv.join(' | ') + '\n';
      }
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Salesforce sosl_search: ' + errMsg(err) } }]; }

} else if (action === 'describe_object') {
  const objectType = input.object_type || input.sobject;
  if (!objectType) return [{ json: { error: 'Parameter "object_type" is required (e.g. Contact, Account, Opportunity, Lead, Case, Task, or a custom object like MyObject__c).' } }];
  try {
    const d = await sfGet('/sobjects/' + encodeURIComponent(objectType) + '/describe');
    let out = 'SObject: ' + d.name + ' (label: ' + d.label + ')\n';
    out += 'Custom: ' + (d.custom ? 'yes' : 'no') + ' | Createable: ' + d.createable + ' | Updateable: ' + d.updateable + ' | Deletable: ' + d.deletable + '\n';
    out += 'Fields (' + (d.fields || []).length + '):\n';
    for (const f of (d.fields || [])) {
      let line = '  ' + f.name + ' (' + f.type + ')';
      if (!f.nillable && f.createable && !f.defaultedOnCreate) line += ' REQUIRED';
      if (f.custom) line += ' [custom]';
      if (f.type === 'picklist' && f.picklistValues && f.picklistValues.length) {
        const active = f.picklistValues.filter(function(p){ return p.active; }).map(function(p){ return p.value; });
        if (active.length) line += ' values=[' + active.slice(0, 10).join(', ') + (active.length > 10 ? ', ...' : '') + ']';
      }
      out += line + '\n';
    }
    return [{ json: { result: truncate(out, 8000) } }];
  } catch (err) { return [{ json: { error: 'Salesforce describe_object: ' + errMsg(err) } }]; }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_contacts, search_contacts, get_contact, create_contact, update_contact, delete_contact, list_accounts, search_accounts, get_account, create_account, update_account, delete_account, list_leads, search_leads, get_lead, create_lead, update_lead, delete_lead, list_opportunities, search_opportunities, get_opportunity, create_opportunity, update_opportunity, delete_opportunity, list_cases, get_case, create_case, update_case, delete_case, list_tasks, create_task, update_task, soql_query, sosl_search, describe_object.' } }];
}
